ST.xhtml:
SUPER^.initialize();

lHeartbeatTimer.Period := T#300MS;
lHeartbeatTimer.Enable := TRUE;
lHeartbeatTimer.initialize();

SUPER^.operator();

lHeartbeatTimer.operator();

IF (Received) THEN
	lHeartbeatTimer.reset();
END_IF

SUPER^.operator();

lHandler(ou32_Handle := lHandle,ot_Msg => lMessage,os16_Status => lReturnStatus);

IF (lReturnStatus=C_NO_ERR) THEN
	lReceivedCount := lReceivedCount + 1;

	lReceived := TRUE;
	lSuccess := TRUE;
	lFinished := TRUE;
	lProceed := TRUE;

	finish();
	RETURN;
END_IF

IF (lReturnStatus<>C_NOACT) THEN
	lReceived := FALSE;
	lSuccess := FALSE;
	lFinished := TRUE;
	lProceed := lProceedOnFail;

	finish();
	RETURN;	
END_IF

lTimer.operator();
IF (lTimer.Expired) THEN
	lReceived := FALSE;
	lSuccess := FALSE;
	lFinished := TRUE;
	lProceed := lProceedOnTimeout;

	finish();
	RETURN;	
END_IF

lReceived := FALSE;

SUPER^.initialize();

lReceivedCount := 0;

lTimer.Enable := TRUE;
lTimer.Period := T#1S;
lTimer.initialize();

SUPER^.initialize();

lSDOReadAttemptCounter := 0;
lSDOReadSuccessCounter := 0;

lSDORead.CHANNEL := 0;
lSDORead.ENABLE := FALSE;
lSDORead.TIMEOUT := 500;
lSDORead.MODE := CIA405.SDO_MODE.AUTO;
lSDORead.DATA := ADR(lSDOReadData);

SUPER^.operator();

IF (lSDORead.ENABLE) THEN
	lSDORead(DATALENGTH:=lSDODReadDataLength);
	IF ((lSDORead.CONFIRM) OR (lSDORead.ERROR<>CIA405.CANOPEN_KERNEL_ERROR.CANOPEN_KERNEL_NO_ERROR)) THEN
		lSDORead.ENABLE := FALSE;
		lSDOReadAttemptCounter := lSDOReadAttemptCounter + 1;
		IF (lSDORead.CONFIRM) THEN
			lSuccess := TRUE;
			lFinished := TRUE;
			lProceed := TRUE;

			sdoReadHandler();
			lSDOReadSuccessCounter := lSDOReadSuccessCounter + 1;

			finish();
			RETURN;
		END_IF
		IF (lSDORead.ERROR<>CIA405.CANOPEN_KERNEL_ERROR.CANOPEN_KERNEL_NO_ERROR) THEN
			lSuccess := FALSE;
			lFinished := TRUE;
			lProceed := TRUE;

			finish();
			RETURN;
		END_IF
	END_IF	
END_IF

SUPER^.initialize();

lSDOWriteAttemptCounter := 0;
lSDOWriteSuccessCounter := 0;

lSDOWrite.CHANNEL := 0;
lSDOWrite.ENABLE := FALSE;
lSDOWrite.TIMEOUT := 500;
lSDOWrite.MODE := CIA405.SDO_MODE.AUTO;
lSDOWrite.DATA := ADR(lSDOWriteData);

SUPER^.operator();

IF (lSDOWrite.ENABLE) THEN
	lSDOWrite();
	IF ((lSDOWrite.CONFIRM) OR (lSDOWrite.ERROR<>CIA405.CANOPEN_KERNEL_ERROR.CANOPEN_KERNEL_NO_ERROR)) THEN
		lSDOWrite.ENABLE := FALSE;
		lSDOWriteAttemptCounter := lSDOWriteAttemptCounter + 1;
		IF (lSDOWrite.CONFIRM) THEN
			lSuccess := TRUE;
			lFinished := TRUE;
			lProceed := TRUE;

			lSDOWriteSuccessCounter := lSDOWriteSuccessCounter + 1;

			finish();
			RETURN;
		END_IF
		IF (lSDOWrite.ERROR<>CIA405.CANOPEN_KERNEL_ERROR.CANOPEN_KERNEL_NO_ERROR) THEN
			lSuccess := FALSE;
			lFinished := TRUE;
			lProceed := TRUE;

			finish();
			RETURN;
		END_IF
	END_IF	
END_IF

SUPER^.operator();

lHandler(lHandle,lMessage,lReturnStatus);

IF (lReturnStatus=C_NO_ERR) THEN
	lTransmittedCount := lTransmittedCount + 1;

	lTransmitted := TRUE;
	lSuccess := TRUE;
	lFinished := TRUE;
	lProceed := TRUE;

	finish();
	RETURN;
END_IF

IF (lReturnStatus<>C_OVERFLOW) THEN
	lTransmitted := FALSE;
	lSuccess := FALSE;
	lFinished := TRUE;
	lProceed := lProceedOnFail;

	finish();
	RETURN;	
END_IF

lTransmitted := FALSE;
lSuccess := FALSE;
lFinished := TRUE;
lProceed := lProceedOnOverflow;

finish();

lHandler(ot_Msg := lMessage,os16_Status => lReturnStatus);

IF (lReturnStatus=C_OVERFLOW) THEN
	lOverflowCount := lOverflowCount + 1;
END_IF

lHandler(ot_Msg := message,os16_Status => lReturnStatus);

IF (lReturnStatus=C_OVERFLOW) THEN
	lOverflowCount := lOverflowCount + 1;
END_IF

transmit := lReturnStatus;

SUPER^.initialize();

lMessage.t_Id.u32_Id := 16#0;
lMessage.t_Id.u8_Xtd := X_OFF;
lMessage.u8_Dlc := 2;
lMessage.au8_Data[0] := 0;
lMessage.au8_Data[1] := 0;

SUPER^.initialize();

lMessage.t_Id.u32_Id := 16#0;
lMessage.t_Id.u8_Xtd := X_OFF;
lMessage.u8_Dlc := 2;
lMessage.au8_Data[0] := 0;
lMessage.au8_Data[1] := 0;

allocate := INT_TO_UINT(id) * cBlockSize;

blocks := REAL_TO_UINT(UDINT_TO_REAL(sz)/USINT_TO_REAL(cBlockSize));
IF ((blocks*cBlockSize)<sz) THEN
	blocks := blocks + 1;
END_IF

lAllocated := MAX(allocate + sz,lAllocated);

IF (lAllocated>(cAllocatedBlockMax*cBlockSize)) THEN
	gCodeErrorHandler(pMessage:='over allocation in PersistenceManager');
END_IF

FOR i:=0 TO cAllocatedBlockMax DO
	lData[i] := 0;
END_FOR

lHandler.ou32_Address := 0;
lHandler.ou32_Count := SIZEOF(lData);
lHandler.opu8_Data := ADR(lData);

lHandler();

lHandler.ou32_Address := MIN(index,cAllocatedBlockMax)*cBlockSize;
lHandler.ou32_Count := cBlockSize;
lHandler.opu8_Data := ADR(data);

lHandler();
read := data;

lHandler.ou32_Address := MIN(index,cAllocatedBlockMax)*cBlockSize;
lHandler.ou32_Count := cBlockSize;
lHandler.opu8_Data := ADR(data);

lHandler();
lFlush();

IF (Value=lValue) THEN
	RETURN;
END_IF

lValue := Value;
write();

lData := ADR(lValue);
lCount := SIZEOF(lValue);

SUPER^.initialize();

IF (lValue=NOT(16#0)) THEN //foobar why?
	lValue := 16#0;
END_IF

IF (Value=lValue) THEN
	RETURN;
END_IF

lValue := Value;
write();

IF (Value=lValue) THEN
	RETURN;
END_IF

lValue := Value;
write();

IF (lValue[0]=255) THEN
	Value := '';
	RETURN;
END_IF

Value := lValue;

IF (strcmp(Value,lValue)) THEN
	RETURN;
END_IF

lValue := Value;
write();

IF (Value=lValue) THEN
	RETURN;
END_IF

lValue := Value;
write();

IF (strcmp(Value,lValue)) THEN
	RETURN;
END_IF

lValue := Value;
write();

IF (lValue[0]=255) THEN
	Value := '';
	RETURN;
END_IF

Value := lValue;

IF (NOT(__ISVALIDREF(store))) THEN
	RETURN;	
END_IF

IF (MEMUtils.MemCmp(ADR(lValue),ADR(store),UDINT_TO_DWORD(lCount))) THEN
	RETURN;
END_IF

MEMUtils.MemCpy(ADR(lValue),ADR(store),UDINT_TO_DWORD(lCount));
write();

IF (Value=lValue) THEN
	RETURN;
END_IF

lValue := Value;
write();

IF (Value=lValue) THEN
	RETURN;
END_IF

lValue := Value;
write();

lAddress := gPersistenceManager.allocate(lCount,lIdentifier,lBlocks);

lReadHandler.ou32_Address := lAddress;
lReadHandler.ou32_Count := lCount;
lReadHandler.opu8_Data := lData;

lWriteHandler.ou32_Address := lAddress;
lWriteHandler.ou32_Count := lCount;
lWriteHandler.opu8_Data := lData;

read();
